module top_module(
	input clk,
	input set,
	input reset,
	input j,
	input k,
	output reg q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		q <= 1'b0;
	else if (set)
		q <= 1'b1;
	else if (j && ~k)
		q <= 1'b1;
	else if (~j && k)
		q <= 1'b0;
	else if (j && k)
		q <= ~q;
end
endmodule
